queries.velociraptor:
SELECT * FROM foreach(
  row=Artifact.Windows.Registry.NTUser(userFilter='.*'),
  query={
    SELECT Key, Value, Mtime
    FROM read_reg_key(glob='HKCU/SOFTWARE/Microsoft/Office/*/Outlook/WebView/Inbox/*')
    WHERE Mtime > now() - 86400
  }
)

